import React, { useState } from "react";
import {
  Box,
  Button,
  TextField,
  Typography,
  Paper,
  IconButton,
  InputAdornment,
  Divider,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Checkbox,
  FormControlLabel,
  LinearProgress,
} from "@mui/material";
import { motion, AnimatePresence } from "motion/react";
import {
  IoEyeOutline,
  IoEyeOffOutline,
  IoArrowForward,
  IoArrowBack,
  IoCheckmark,
} from "react-icons/io5";
import { LuChevronDown } from "react-icons/lu";

const MotionPaper = motion.create(Paper);
const MotionBox = motion.create(Box);
const MotionButton = motion.create(Button);

const MultiStepForm = () => {
  const [showPassword, setShowPassword] = useState(false);
  const [activeStep, setActiveStep] = useState(0);
  const [formData, setFormData] = useState({});

  const handleInputChange = (field, value) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const handleNext = () => {
    setActiveStep((prev) => prev + 1);
  };

  const handleBack = () => {
    setActiveStep((prev) => prev - 1);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Form submitted:", formData);
  };

  const steps = ["Personal", "Contact", "Preferences"];

  const stepContent = [
    // Step 1: Personal Info
    <MotionBox
      key="step1"
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -20 }}
      transition={{ duration: 0.25, ease: "easeOut" }}
      sx={{ display: "flex", flexDirection: "column", gap: 3 }}
    >
      <Box sx={{ display: "flex", gap: 2 }}>
        <TextField
          fullWidth
          label="First Name"
          variant="outlined"
          size="small"
          onChange={(e) => handleInputChange("firstName", e.target.value)}
        />
        <TextField
          fullWidth
          label="Last Name"
          variant="outlined"
          size="small"
          onChange={(e) => handleInputChange("lastName", e.target.value)}
        />
      </Box>
      <TextField
        fullWidth
        label="Email address"
        type="email"
        variant="outlined"
        size="small"
        onChange={(e) => handleInputChange("email", e.target.value)}
      />
      <TextField
        fullWidth
        label="Create password"
        type={showPassword ? "text" : "password"}
        variant="outlined"
        size="small"
        InputProps={{
          endAdornment: (
            <InputAdornment position="end">
              <IconButton
                onClick={() => setShowPassword(!showPassword)}
                edge="end"
                size="small"
              >
                {showPassword ? <IoEyeOffOutline /> : <IoEyeOutline />}
              </IconButton>
            </InputAdornment>
          ),
        }}
        onChange={(e) => handleInputChange("password", e.target.value)}
      />
    </MotionBox>,

    // Step 2: Contact Details
    <MotionBox
      key="step2"
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -20 }}
      transition={{ duration: 0.25, ease: "easeOut" }}
      sx={{ display: "flex", flexDirection: "column", gap: 3 }}
    >
      <TextField
        fullWidth
        label="Phone Number"
        variant="outlined"
        size="small"
        onChange={(e) => handleInputChange("phone", e.target.value)}
      />
      <TextField
        fullWidth
        label="Address"
        variant="outlined"
        size="small"
        multiline
        rows={2}
        onChange={(e) => handleInputChange("address", e.target.value)}
      />
      <FormControl fullWidth size="small">
        <InputLabel>Country</InputLabel>
        <Select
          value={formData.country || ""}
          label="Country"
          onChange={(e) => handleInputChange("country", e.target.value)}
          IconComponent={LuChevronDown}
        >
          <MenuItem value="us">United States</MenuItem>
          <MenuItem value="uk">United Kingdom</MenuItem>
          <MenuItem value="ca">Canada</MenuItem>
          <MenuItem value="au">Australia</MenuItem>
        </Select>
      </FormControl>
    </MotionBox>,

    // Step 3: Preferences
    <MotionBox
      key="step3"
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -20 }}
      transition={{ duration: 0.25, ease: "easeOut" }}
      sx={{ display: "flex", flexDirection: "column", gap: 2 }}
    >
      <Box sx={{ display: "flex", flexDirection: "column", gap: 1 }}>
        <FormControlLabel
          control={
            <Checkbox
              size="small"
              onChange={(e) =>
                handleInputChange("emailNotifications", e.target.checked)
              }
            />
          }
          label="Email notifications"
        />
        <FormControlLabel
          control={
            <Checkbox
              size="small"
              onChange={(e) =>
                handleInputChange("smsNotifications", e.target.checked)
              }
            />
          }
          label="SMS notifications"
        />
        <FormControlLabel
          control={
            <Checkbox
              size="small"
              onChange={(e) =>
                handleInputChange("newsletter", e.target.checked)
              }
            />
          }
          label="Newsletter subscription"
        />
      </Box>
      <TextField
        fullWidth
        label="Additional comments"
        multiline
        rows={3}
        variant="outlined"
        size="small"
        placeholder="Tell us how we can help you..."
        onChange={(e) => handleInputChange("comments", e.target.value)}
      />
    </MotionBox>,
  ];

  return (
    <MotionPaper
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3, ease: "easeOut" }}
      sx={{ p: 4, maxWidth: 420 }}
    >
      <Typography variant="h5" sx={{ fontWeight: 500, mb: 1, textAlign: "center" }}>
        Create Account
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 4, textAlign: "center" }}>
        Complete all steps to create your account
      </Typography>

      <Box sx={{ mb: 2 }}>
        <Box sx={{ display: "flex", justifyContent: "space-between", mb: 1 }}>
          <Typography variant="body2" sx={{ fontWeight: 500 }}>
            Step {activeStep + 1} / {steps.length}
          </Typography>
          <Typography variant="body2" sx={{ fontWeight: 500 }}>
            {steps[activeStep]}
          </Typography>
        </Box>
        <LinearProgress
          variant="determinate"
          value={((activeStep + 1) / steps.length) * 100}
          sx={{ height: 6, borderRadius: 3 }}
        />
      </Box>

      <form onSubmit={handleSubmit}>
        <AnimatePresence mode="wait">
          {stepContent[activeStep]}
        </AnimatePresence>

        <Box sx={{ display: "flex", justifyContent: "space-between", mt: 4, gap: 2 }}>
          <MotionButton
            disabled={activeStep === 0}
            onClick={handleBack}
            startIcon={<IoArrowBack />}
            variant="outlined"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            transition={{ duration: 0.2, ease: "easeOut" }}
          >
            Back
          </MotionButton>

          <MotionButton
            variant="contained"
            onClick={activeStep === steps.length - 1 ? handleSubmit : handleNext}
            endIcon={activeStep === steps.length - 1 ? <IoCheckmark /> : <IoArrowForward />}
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            transition={{ duration: 0.2, ease: "easeOut" }}
          >
            {activeStep === steps.length - 1 ? "Complete" : "Continue"}
          </MotionButton>
        </Box>
      </form>
    </MotionPaper>
  );
};

export default MultiStepForm;

